sql:
SELECT job_title
FROM jobs
WHERE job_id = 1;

external_knowledge:
- "sowing seeds" represents the job titles; 
- "gardeners" represent the applications; 
- "earliest planting date" is analogous to the earliest application deadline for each job; 
- "by the end of the year" refers to the deadline being on or before December 31, 2023.

sql:
SELECT T1.job_title
FROM jobs AS T1
INNER JOIN departments AS T2 ON T1.department = T2.department_name;

SELECT a.applicant_name, j.job_title
FROM applications a
INNER JOIN jobs j ON a.job_id = j.job_id;
